        </div>
      </aside>

      <div className="flex-1 flex flex-col min-w-0 transition-all duration-300">
        {isOffline && (
          <div className="bg-slate-900 text-white text-xs font-bold py-1 px-4 flex items-center justify-center gap-2">
            <WifiOff size={12} className="animate-pulse" />
            <span>You are currently offline. Changes will sync when connection is restored.</span>
          </div>
        )}
        <header className="h-header bg-panel border-b border-default flex items-center justify-between sticky top-0 z-sticky shadow-sm shrink-0 px-layout">
