  // --- ACTIONS MEMOIZATION ---
  const actions = useMemo(() => ({
    setGlobalSearch: (s: string) => setState(prev => ({ ...prev, globalSearch: s })),
    setDesignerDraft: (draft: any) => setState(prev => ({ ...prev, designerDraft: draft })),
